parameters.inputSchema:
={
  "type": "object",
  "properties": {
    "ResumenIA": {
      "type": "string",
      "description": "Resumen breve en una frase de lo que quiere el lead (tipo de operación, inmueble, zona y presupuesto si se menciona)."
    },
    "TipoClienteIA": {
      "type": "string",
      "description": "Tipo de cliente clasificado por la IA.",
      "enum": [
        "familia",
        "inversor",
        "joven profesional",
        "empresa",
        "estudiante",
        "jubilado",
        "pareja",
        "otro"
      ]
    },
    "LeadScoreIA": {
      "type": "integer",
      "description": "Probabilidad de cierre o nivel de interés entre 0 y 100.",
      "minimum": 0,
      "maximum": 100
    },
    "UrgenciaIA": {
      "type": "string",
      "description": "Nivel de urgencia percibida.",
      "enum": [
        "Alta",
        "Media",
        "Baja"
      ]
    },
    "SentimientoIA": {
      "type": "string",
      "description": "Percepción general del tono del lead.",
      "enum": [
        "Muy interesado",
        "Interesado",
        "Solo curioseando",
        "Molesto",
        "Escéptico"
      ]
    }
  },
  "required": [
    "ResumenIA",
    "TipoClienteIA",
    "LeadScoreIA",
    "UrgenciaIA",
    "SentimientoIA"
  ],
  "additionalProperties": false
}
